MonsterListener = {}

function MonsterListener:init()
    CreatureAttackPlayerEvent.registerCallBack(self.onCreatureAttackPlayer)
    CreatureAttackCreatureEvent.registerCallBack(self.onCreatureAttackCreature)
end

function MonsterListener.onCreatureAttackPlayer(targetId, thowerId)
    local player = PlayerManager:getPlayerByEntityId(targetId)
    if player == nil then
        return
    end

    local monster = MonsterManager:getMonster(thowerId)
    if monster ~= nil then
        if player:onAttacked(monster, Define.TargetType.TargetMonster) then
            monster:onAttack(player, Define.TargetType.TargetPlayer)
        end
    end

    local robot = RobotManager:getRobot(thowerId)
    if robot ~= nil then
        robot:onAttackPlayer(player)
    end
end

function MonsterListener.onCreatureAttackCreature(targetId, thowerId)
    --攻击者是怪物
    local monster = MonsterManager:getMonster(thowerId)
    if monster == nil then
        return false
    end

    --被击者是机器人
    local robot = RobotManager:getRobot(targetId)
    if robot == nil then
        return false
    end

    robot:onAttackedByMonster(monster)

    return true
end

return MonsterListener